import requests
from requests.auth import HTTPBasicAuth

# RabbitMQ server details
RABBITMQ_URL = 'http://localhost:15672'
ADMIN_USER = 'admin'
ADMIN_PASSWORD = 'password'

# Virtual hosts and users
vhosts = {
    'app1': {'user': 'app1_user', 'password': 'app1_password'},
    'app2': {'user': 'app2_user', 'password': 'app2_password'}
}

def create_vhost(vhost_name):
    url = f'{RABBITMQ_URL}/api/vhosts/{vhost_name}'
    response = requests.put(url, auth=HTTPBasicAuth(ADMIN_USER, ADMIN_PASSWORD))
    if response.status_code == 201:
        print(f'Vhost {vhost_name} created successfully.')
    else:
        print(f'Failed to create vhost {vhost_name}: {response.text}')

def set_permissions(vhost_name, user, password):
    url = f'{RABBITMQ_URL}/api/permissions/{vhost_name}/{user}'
    payload = {
        'configure': '.*',
        'write': '.*',
        'read': '.*'
    }
    response = requests.put(url, auth=HTTPBasicAuth(ADMIN_USER, ADMIN_PASSWORD), json=payload)
    if response.status_code == 201:
        print(f'Permissions set for {user} on vhost {vhost_name}.')
    else:
        print(f'Failed to set permissions for {user} on vhost {vhost_name}: {response.text}')

def create_user_and_set_permissions(vhost_name, user, password):
    url = f'{RABBITMQ_URL}/api/users/{user}'
    payload = {
        'password': password,
        'tags': ''
    }
    response = requests.put(url, auth=HTTPBasicAuth(ADMIN_USER, ADMIN_PASSWORD), json=payload)
    if response.status_code == 201:
        print(f'User {user} created successfully.')
        set_permissions(vhost_name, user, password)
    else:
        print(f'Failed to create user {user}: {response.text}')

if __name__ == '__main__':
    for vhost_name, details in vhosts.items():
        create_vhost(vhost_name)
        create_user_and_set_permissions(vhost_name, details['user'], details['password'])